<?php declare(strict_types=1); ?>
<?php require base_path('app/Views/partials/settings-nav.php'); ?>
<div class="card content-card"><div class="card-body p-4"><div class="mb-4"><h5 class="mb-1">System Settings</h5><p class="text-muted mb-0">Maintain core application, leave, and UI configuration values from one place.</p></div><?php if (($settings ?? []) === []): ?><div class="empty-state">No settings are available yet.</div><?php else: ?><div class="row g-4"><?php foreach ($settings as $category => $items): ?><div class="col-12"><div class="border rounded p-3"><div class="d-flex justify-content-between align-items-center mb-3"><h6 class="mb-0"><?= e(ucwords(str_replace('_', ' ', (string) $category))); ?></h6><span class="badge text-bg-light"><?= e((string) count($items)); ?> item(s)</span></div><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Setting</th><th>Value</th><th class="text-end">Action</th></tr></thead><tbody><?php foreach ($items as $setting): ?><tr><td><div class="fw-semibold"><?= e(ucwords(str_replace('_', ' ', (string) $setting['setting_key']))); ?></div><div class="small text-muted">Type: <?= e((string) $setting['value_type']); ?> • Updated: <?= e((string) $setting['updated_at']); ?></div></td><td style="min-width: 280px;"><form method="post" action="<?= e(url('/settings/' . $setting['id'] . '/update')); ?>"><?= csrf_field(); ?><?php if ((string) $setting['value_type'] === 'boolean'): ?><select name="setting_value" class="form-select"><option value="1" <?= (string) ($setting['setting_value'] ?? '') === '1' ? 'selected' : ''; ?>>True</option><option value="0" <?= (string) ($setting['setting_value'] ?? '') === '0' ? 'selected' : ''; ?>>False</option></select><?php elseif (in_array((string) $setting['value_type'], ['json', 'text'], true)): ?><textarea name="setting_value" class="form-control" rows="3"><?= e((string) ($setting['setting_value'] ?? '')); ?></textarea><?php else: ?><input type="text" name="setting_value" class="form-control" value="<?= e((string) ($setting['setting_value'] ?? '')); ?>"><?php endif; ?></td><td class="text-end"><button type="submit" class="btn btn-sm btn-primary">Save</button></form></td></tr><?php endforeach; ?></tbody></table></div></div></div><?php endforeach; ?></div><?php endif; ?></div></div>